    @Override
    public BigDecimal getInhoudingRsz(SleutelGegevens gegevens) {
        LocalDate datum = TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode);
        return getInhoudingRsz(gegevens, datum);
    }

    @Override
    public BigDecimal getInhoudingRsz(SleutelGegevens gegevens, LocalDate zoekDatum) {
        RszConstantOld constante =
                rszConstantOldService.getByCategoriePensioenStelselEnDatum(gegevens.getCategorie(), gegevens.getPensioenStelsel(), zoekDatum);
        checkRszConstantGevonden(constante, gegevens);
        return getRszPercentage(constante);
    }

    private BigDecimal getRszPercentage(RszConstantOld constante) {
        BigDecimal inhoudingPercentage = BigDecimal.ZERO;
        if (constante != null) {
            inhoudingPercentage = constante.getWerknemerZivGezondheid();
            inhoudingPercentage = inhoudingPercentage.add(constante.getWerknemerZivUitkering());
            inhoudingPercentage = inhoudingPercentage.add(constante.getWerknemerWerkloosheid());
            inhoudingPercentage = inhoudingPercentage.add(constante.getWerknermerPensioen());
            inhoudingPercentage = inhoudingPercentage.add(constante.getWerknermerSolidariteitsBijdrage());
            inhoudingPercentage = inhoudingPercentage.movePointLeft(2);
        }
        return inhoudingPercentage;
    }

    private void checkRszConstantGevonden(RszConstantOld constante, SleutelGegevens gegevens) {
        if (constante == null) {
            regulManager.doRegulException(gegevens.getOpdracht(), Regulkode.RSZ_CONSTANTEN_NIET_GEVONDEN);
        }
    }

