        return getPatronaalPercentage(constante);
    }

    private BigDecimal getPatronaalPercentage(RszConstantOld constante) {
        BigDecimal bijdragePercentage = BigDecimal.ZERO;
        if (constante != null) {
            bijdragePercentage = constante.getKinderBijslag();
            bijdragePercentage = bijdragePercentage.add(constante.getWerkgeverZivGezondheid());
            bijdragePercentage = bijdragePercentage.add(constante.getWerkgeverZivUitkering());
            bijdragePercentage = bijdragePercentage.add(constante.getWerkgeverWerkloosheid());
            bijdragePercentage = bijdragePercentage.add(constante.getWerkgeverPensioen());
            bijdragePercentage = bijdragePercentage.add(constante.getWerkgeverSolidariteitsBijdrage());
            bijdragePercentage = bijdragePercentage.add(constante.getBeroepsZiekte());
            bijdragePercentage = bijdragePercentage.add(constante.getArbeidsOngeval());
            bijdragePercentage = bijdragePercentage.add(constante.getLoonmatiging());
            bijdragePercentage = bijdragePercentage.add(constante.getFcud());
            bijdragePercentage = bijdragePercentage.movePointLeft(2);
        }
        return bijdragePercentage;
    }

