    @Override
    public BigDecimal bepaal(ContextKey bijdrageKey, SleutelGegevens gegevens, LocalDate zoekDatum) {
        BigDecimal percentageBijdrage = BigDecimal.ZERO;
        if (bijdrageKey == BIJDRAGE_RSZ_KEY) {
            percentageBijdrage = getInhoudingRsz(gegevens, zoekDatum);
        } else if (bijdrageKey == PATRONALE_BIJDRAGE_RSZ_KEY || (bijdrageKey == PATRONALE_BIJDRAGE_ERKENTELIJKHEIDSPREMIE_KEY &&
                (gegevens.getHoedanigheid() == Hoedanigheid.VRIJWILLIGE_BRANDWEER_ERKENTELIJKHEIDSPREMIE ||
                        gegevens.getHoedanigheid() == Hoedanigheid.ERKENTELIJKHEIDSPREMIE))) {
            percentageBijdrage = getPatronaleBijdrageRsz(gegevens, zoekDatum);
        } else if (bijdrageKey == PATRONALE_BIJDRAGE_ERKENTELIJKHEIDSPREMIE_KEY) {
            percentageBijdrage = getPatronaleBijdrageErkentelijkheidsPremie(gegevens, zoekDatum);
        } else if (bijdrageKey == BIJDRAGE_OVERUREN_GECO_KEY) {
            percentageBijdrage = getInhoudingOverurenGeco(gegevens, zoekDatum);
        } else if (bijdrageKey == PATRONALE_BIJDRAGE_OVERUREN_GECO_KEY) {
            percentageBijdrage = getPatronaleBijdrageOverurenGeco(gegevens, zoekDatum);
        } else if (bijdrageKey == BIJDRAGE_PENSIOEN_VASTBENOEMDEN_KEY) {
            percentageBijdrage = getInhoudingBijdragePensioen(gegevens, zoekDatum);
        } else if (bijdrageKey == PATRONALE_BIJDRAGE_PENSIOEN_VASTBENOEMDEN_KEY) {
            percentageBijdrage = getPatronaleBijdragePensioen(gegevens, zoekDatum);
        } else if (bijdrageKey == BIJDRAGE_PENSIOEN_VASTBENOEMDEN_APK_KEY) {
            percentageBijdrage = getInhoudingPensioenVastbenoemdenApk(gegevens, zoekDatum);
        } else if (bijdrageKey == PATRONALE_BIJDRAGE_PENSIOEN_VASTBENOEMDEN_APK_KEY) {
            percentageBijdrage = getPatronaleBijdragePensioenVastbenoemdenApk(gegevens, zoekDatum);
        } else if (bijdrageKey == BIJDRAGE_DUBBEL_VAKANTIEGELD_KEY) {
            percentageBijdrage = getInhoudingDubbelVakantiegeld(gegevens, zoekDatum);
        } else if (bijdrageKey == PATRONALE_BIJDRAGE_VOERTUIG_KEY) {
            percentageBijdrage = constantManager.getActualConstant(Konstanten.KST_PCT_SOLBIJDRAGE_VOERTUIG, rekenTijd).getProcentFactor();
        } else if (bijdrageKey == PATRONALE_BIJDRAGE_MEER_DAN_10WERKNEMERS_KEY) {
            percentageBijdrage = getPatronaleBijdrageMeerDan10Werknemers(gegevens, zoekDatum);
        } else if (bijdrageKey == BIJDRAGE_PENSIOEN_MANDATARIS_KEY) {
            percentageBijdrage = constantManager.getActualConstant(Konstanten.KST_PCT_PENS_INH_NBMAND, rekenTijd).getProcentFactor();
        } else if (bijdrageKey == PATRONALE_BIJDRAGE_PENSIOEN_MANDATARIS_KEY) {
            percentageBijdrage = constantManager.getActualConstant(Konstanten.KST_PCT_PENS_BIJDR_NBMAND, rekenTijd).getProcentFactor();
        } else {
            log.warn("Voor {} is geen percentage gedefinieerd", bijdrageKey);
        }
        log.trace("percentageBijdrage {}:{}", bijdrageKey, percentageBijdrage);
        return percentageBijdrage;
    }
